#include<bits/stdc++.h>
using namespace std;
int w[2001],h[2001],dp[2001];
int main()
{
    int n,l;
    scanf("%d%d",&n,&l);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&h[i],&w[i]);
    }
    int sum=0,max1=0,ans=0;
    for(int i=1;i<=n;i++)
    {
        dp[i]=dp[i-1]+h[i];
        int h1=h[i],w1=w[i];
        for(int j=i-1;j>=1;j--)
        {
            w1+=w[j];
            if(w1>l)
            {
                continue;
            }
            h1=max(h1,h[j]);
            dp[i]=min(dp[i],dp[j-1]+h1);
        }
    }
    printf("%d",dp[n]);
    return 0;
}
